det_check_template:
proof fn det_replace<V>(self_: PPtr<V>, pre_perm: PointsTo<V>, in_v: V, post1_perm: PointsTo<V>, r1: V, post2_perm: PointsTo<V>, r2: V)
    requires (pre_perm.pptr() == self_), (pre_perm.is_init()),
    ensures
        ({
            &&& (post1_perm.pptr() == pre_perm.pptr())
            &&& (post1_perm.mem_contents() == MemContents::Init(in_v))
            &&& (r1 == pre_perm.value())
            &&& (post2_perm.pptr() == pre_perm.pptr())
            &&& (post2_perm.mem_contents() == MemContents::Init(in_v))
            &&& (r2 == pre_perm.value())
        }) ==> det_replace_equal::<V>(r1, r2, post1_perm, post2_perm),
{
    reveal(PointsTo::addr);
    reveal(PointsTo::mem_contents);
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_replace_equal<V>(r1: V, r2: V, post1_perm: PointsTo<V>, post2_perm: PointsTo<V>) -> bool {
    (r1 == r2)
    && (((post1_perm).is_init() == (post2_perm).is_init()) && ((post1_perm).ptr().addr() == (post2_perm).ptr().addr()) && ((post1_perm).is_init() ==> ((post1_perm).value() == (post2_perm).value())))
}
